    @XmlElement
    private String confirmationNumber;

    @XmlElement
    private Date processedAt;

    public TransactionResponse() {
        this.processedAt = new Date();
    }

    public static TransactionResponse success(String transactionId, String confirmationNumber) {
        TransactionResponse response = new TransactionResponse();
        response.setResponseId(java.util.UUID.randomUUID().toString());
        response.setTransactionId(transactionId);
        response.setStatus(TransactionStatus.SUCCESS);
        response.setConfirmationNumber(confirmationNumber);
        response.setMessage("Transaction processed successfully");
        return response;
    }

    public static TransactionResponse failure(String transactionId, String message) {
        TransactionResponse response = new TransactionResponse();
        response.setResponseId(java.util.UUID.randomUUID().toString());
        response.setTransactionId(transactionId);
        response.setStatus(TransactionStatus.FAILED);
        response.setMessage(message);
        return response;
    }

